#!/usr/bin/perl

use strict;
use warnings;

use CGI;
use Storable qw(nstore retrieve);
use Fcntl qw(:flock); # For file locking

# --- Configuration ---
my $SESSION_DIR = "/tmp"; # Directory to store session files
my $SESSION_COOKIE_NAME = "myapp_session_id";
my $SESSION_TIMEOUT_SECONDS = 3600; # 1 hour

# --- Global CGI object ---
my $q = CGI->new;

# --- Session Data Structure ---
# This is an example. You can put anything you want in here.
# For simplicity, we'll use a hash reference.
my $session_data = {};
my $session_id;
my $session_file_path;
my $session_file_handle;

# --- Function to initialize or load a session ---
sub init_session {
    $session_id = $q->cookie($SESSION_COOKIE_NAME);

    if ($session_id) {
        $session_file_path = "$SESSION_DIR/sess_$session_id";

        # Try to open and lock the session file
        if (open($session_file_handle, "+<", $session_file_path)) {
            flock($session_file_handle, LOCK_EX) or die "Cannot lock session file $session_file_path: $!";

            # Check if the session file is empty or invalid
            if (-s $session_file_path > 0) {
                eval {
                    $session_data = retrieve($session_file_handle);
                };
                if ($@) {
                    warn "Error retrieving session data from $session_file_path: $@. Creating new session.";
                    close $session_file_handle; # Close the bad file
                    unlink $session_file_path; # Delete the bad file
                    $session_id = undef; # Force new session creation
                } else {
                    # Check for session timeout
                    if (exists $session_data->{_last_access} && (time - $session_data->{_last_access} > $SESSION_TIMEOUT_SECONDS)) {
                        warn "Session $session_id timed out. Creating new session.";
                        close $session_file_handle;
                        unlink $session_file_path;
                        $session_id = undef;
                    }
                }
            } else {
                warn "Session file $session_file_path is empty. Creating new session.";
                close $session_file_handle;
                unlink $session_file_path;
                $session_id = undef;
            }
        } else {
            warn "Could not open session file $session_file_path: $!. Creating new session.";
            $session_id = undef;
        }
    }

    # If no valid session was loaded, create a new one
    unless ($session_id) {
        $session_id = generate_session_id();
        $session_file_path = "$SESSION_DIR/sess_$session_id";

        # Create and lock a new session file
        open($session_file_handle, "+>", $session_file_path) or die "Cannot create session file $session_file_path: $!";
        flock($session_file_handle, LOCK_EX) or die "Cannot lock new session file $session_file_path: $!";

        $session_data = {}; # Initialize empty session data
    }

    # Update last access time
    $session_data->{_last_access} = time;

    # Set the session cookie
    print $q->header(
        -cookie => $q->cookie(
            -name    => $SESSION_COOKIE_NAME,
            -value   => $session_id,
            -expires => '+1h', # Or a longer period, or '0' for session-only
            -path    => '/',
            -httponly => 1, # Important for security
            -secure  => 0, # Set to 1 if using HTTPS
        )
    );
}

# --- Function to save session data ---
sub save_session {
    # Ensure we are at the beginning of the file for nstore
    seek $session_file_handle, 0, 0;
    truncate $session_file_handle, 0; # Clear existing content

    nstore($session_data, $session_file_handle) or die "Cannot store session data to $session_file_path: $!";

    # Release the lock and close the file
    flock($session_file_handle, LOCK_UN) or die "Cannot unlock session file $session_file_path: $!";
    close $session_file_handle;
}

# --- Function to destroy a session ---
sub destroy_session {
    if ($session_id && $session_file_path) {
        # Close and unlock the file if it's open
        if (defined fileno($session_file_handle)) {
            flock($session_file_handle, LOCK_UN) or warn "Cannot unlock session file $session_file_path: $!";
            close $session_file_handle;
        }
        unlink $session_file_path or warn "Could not delete session file $session_file_path: $!";
    }
    $session_data = {}; # Clear in-memory data
    $session_id = undef;

    # Expire the cookie
    print $q->header(
        -cookie => $q->cookie(
            -name    => $SESSION_COOKIE_NAME,
            -value   => '',
            -expires => '-1d', # Expire immediately
            -path    => '/',
            -httponly => 1,
            -secure  => 0,
        )
    );
}

# --- Helper function to generate a unique session ID ---
sub generate_session_id {
    my $id = '';
    # Generate a reasonably unique ID using time, pid, and random number
    $id = join '', map { sprintf "%02x", rand 256 } 1..16; # 16 bytes of random hex
    $id .= sprintf "_%x_%x", time, $$; # Add timestamp and PID for extra uniqueness
    return $id;
}

